"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState, useCallback } from "react";

interface AdminStats {
  totalRooms: number;
  totalBookings: number;
  totalReviews: number;
  totalUsers: number;
  totalRevenue: number;
}

interface AdminRoom {
  id: string;
  name: string;
  description: string;
  price: number;
  capacity: number;
  images: string;
  amenities: string;
  _count: { bookings: number; reviews: number; favorites: number };
}

interface AdminBooking {
  id: string;
  status: string;
  paymentStatus: string;
  checkIn: string;
  checkOut: string;
  totalPrice: number;
  guests: number;
  user: { name: string; email: string };
  room: { name: string };
}

interface AdminReview {
  id: string;
  rating: number;
  comment: string;
  createdAt: string;
  user: { name: string; email: string };
  room: { name: string };
}

interface AdminUser {
  id: string;
  name: string;
  email: string;
  role: string;
  createdAt: string;
  _count: { bookings: number; reviews: number; favorites: number };
}

const adminTabs = [
  { key: "overview", label: "Overview", icon: "📊" },
  { key: "rooms", label: "Rooms", icon: "🏠" },
  { key: "bookings", label: "Bookings", icon: "📅" },
  { key: "reviews", label: "Reviews", icon: "⭐" },
  { key: "users", label: "Users", icon: "👥" },
];

function formatDate(dateStr: string) {
  return new Date(dateStr).toLocaleDateString("en-GB", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });
}

export default function AdminPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [activeTab, setActiveTab] = useState("overview");

  const [stats, setStats] = useState<AdminStats | null>(null);
  const [rooms, setRooms] = useState<AdminRoom[]>([]);
  const [bookings, setBookings] = useState<AdminBooking[]>([]);
  const [reviews, setReviews] = useState<AdminReview[]>([]);
  const [users, setUsers] = useState<AdminUser[]>([]);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Room form state
  const [showRoomForm, setShowRoomForm] = useState(false);
  const [editingRoom, setEditingRoom] = useState<AdminRoom | null>(null);
  const [roomForm, setRoomForm] = useState({
    name: "",
    description: "",
    price: "",
    capacity: "",
    images: "",
    amenities: "",
  });

  // Booking status update
  const [updatingBooking, setUpdatingBooking] = useState<string | null>(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const [statsRes, roomsRes, bookingsRes, reviewsRes, usersRes] =
        await Promise.all([
          fetch("/api/admin/dashboard"),
          fetch("/api/admin/rooms"),
          fetch("/api/admin/bookings"),
          fetch("/api/admin/reviews"),
          fetch("/api/admin/users"),
        ]);

      if (statsRes.ok) setStats(await statsRes.json().then((d) => d.stats));
      if (roomsRes.ok) setRooms(await roomsRes.json());
      if (bookingsRes.ok) setBookings(await bookingsRes.json());
      if (reviewsRes.ok) setReviews(await reviewsRes.json());
      if (usersRes.ok) setUsers(await usersRes.json());
    } catch (err) {
      setError("Failed to load admin data");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/login");
      return;
    }
    if (status === "authenticated" && (session.user as any)?.role !== "admin") {
      router.push("/");
      return;
    }
    if (status === "authenticated") {
      fetchData();
    }
  }, [status, router, fetchData, session]);

  async function handleDeleteRoom(roomId: string) {
    if (!confirm("Delete this room?")) return;
    try {
      const res = await fetch(`/api/admin/rooms?id=${roomId}`, {
        method: "DELETE",
      });
      if (res.ok) {
        setRooms((prev) => prev.filter((r) => r.id !== roomId));
        setStats((prev) =>
          prev ? { ...prev, totalRooms: prev.totalRooms - 1 } : prev
        );
      }
    } catch {
      // ignore
    }
  }

  async function handleDeleteReview(reviewId: string) {
    if (!confirm("Delete this review?")) return;
    try {
      const res = await fetch(`/api/reviews?id=${reviewId}`, {
        method: "DELETE",
      });
      if (res.ok) {
        setReviews((prev) => prev.filter((r) => r.id !== reviewId));
      }
    } catch {
      // ignore
    }
  }

  async function handleUpdateBookingStatus(bookingId: string, newStatus: string) {
    setUpdatingBooking(bookingId);
    try {
      const res = await fetch(`/api/admin/bookings`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ bookingId, status: newStatus }),
      });
      if (res.ok) {
        setBookings((prev) =>
          prev.map((b) => (b.id === bookingId ? { ...b, status: newStatus } : b))
        );
      }
    } catch {
      // ignore
    } finally {
      setUpdatingBooking(null);
    }
  }

  async function handleUpdateUserRole(userId: string, newRole: string) {
    try {
      const res = await fetch("/api/admin/users", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId, role: newRole }),
      });
      if (res.ok) {
        setUsers((prev) =>
          prev.map((u) => (u.id === userId ? { ...u, role: newRole } : u))
        );
      }
    } catch {
      // ignore
    }
  }

  async function handleSaveRoom(e: React.FormEvent) {
    e.preventDefault();
    try {
      const method = editingRoom ? "PUT" : "POST";
      const res = await fetch("/api/admin/rooms", {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(editingRoom ? { ...roomForm, id: editingRoom.id } : roomForm),
      });
      if (res.ok) {
        fetchData();
        setShowRoomForm(false);
        setEditingRoom(null);
        setRoomForm({ name: "", description: "", price: "", capacity: "", images: "", amenities: "" });
      }
    } catch {
      // ignore
    }
  }

  function openEditRoom(room: AdminRoom) {
    setEditingRoom(room);
    setRoomForm({
      name: room.name,
      description: room.description,
      price: room.price.toString(),
      capacity: room.capacity.toString(),
      images: room.images,
      amenities: room.amenities,
    });
    setShowRoomForm(true);
  }

  if (status === "loading") {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#FAF3E0]">
        <div className="animate-spin rounded-full h-12 w-12 border-4 border-[#1A4B7A] border-t-[#E8A435]"></div>
      </div>
    );
  }

  if ((session?.user as any)?.role !== "admin") return null;

  return (
    <div className="min-h-screen bg-[#FAF3E0] pt-24 pb-16">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="font-playfair text-3xl font-bold text-[#1A4B7A] mb-6">
          Admin Dashboard
        </h1>

        {/* Tabs */}
        <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
          {adminTabs.map((tab) => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                activeTab === tab.key
                  ? "bg-[#1A4B7A] text-[#FAF3E0]"
                  : "bg-white text-gray-700 hover:bg-[#FAF3E0]"
              }`}
            >
              <span>{tab.icon}</span>
              {tab.label}
            </button>
          ))}
        </div>

        {error && (
          <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-6">
            {error}
          </div>
        )}

        {loading ? (
          <div className="flex items-center justify-center py-16">
            <div className="animate-spin rounded-full h-10 w-10 border-4 border-[#1A4B7A] border-t-[#E8A435]"></div>
          </div>
        ) : (
          <>
            {/* Overview Tab */}
            {activeTab === "overview" && stats && (
              <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
                {[
                  { label: "Total Bookings", value: stats.totalBookings, color: "#1A4B7A", icon: "📅" },
                  { label: "Revenue", value: `€${stats.totalRevenue.toLocaleString()}`, color: "#5A8F6E", icon: "💰" },
                  { label: "Users", value: stats.totalUsers, color: "#C75B39", icon: "👥" },
                  { label: "Rooms", value: stats.totalRooms, color: "#E8A435", icon: "🏠" },
                  { label: "Reviews", value: stats.totalReviews, color: "#1A4B7A", icon: "⭐" },
                ].map((stat) => (
                  <div
                    key={stat.label}
                    className="bg-white rounded-xl shadow-md p-6 text-center"
                  >
                    <div className="text-3xl mb-2">{stat.icon}</div>
                    <div
                      className="text-2xl font-playfair font-bold"
                      style={{ color: stat.color }}
                    >
                      {stat.value}
                    </div>
                    <div className="text-sm text-gray-600 mt-1">{stat.label}</div>
                  </div>
                ))}
              </div>
            )}

            {/* Rooms Tab */}
            {activeTab === "rooms" && (
              <div>
                <div className="flex items-center justify-between mb-4">
                  <h2 className="font-playfair text-xl font-bold text-[#1A4B7A]">
                    Manage Rooms
                  </h2>
                  <button
                    onClick={() => {
                      setEditingRoom(null);
                      setRoomForm({ name: "", description: "", price: "", capacity: "", images: "", amenities: "" });
                      setShowRoomForm(!showRoomForm);
                    }}
                    className="bg-[#C75B39] text-[#FAF3E0] px-4 py-2 rounded-lg text-sm font-medium hover:bg-[#C75B39]/90 transition-colors"
                  >
                    {showRoomForm ? "Cancel" : "+ Add Room"}
                  </button>
                </div>

                {showRoomForm && (
                  <form
                    onSubmit={handleSaveRoom}
                    className="bg-white rounded-xl shadow-lg p-6 mb-6 space-y-3"
                  >
                    <h3 className="font-playfair text-lg font-bold text-[#1A4B7A]">
                      {editingRoom ? "Edit Room" : "New Room"}
                    </h3>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                      <input
                        type="text"
                        placeholder="Room name"
                        value={roomForm.name}
                        onChange={(e) => setRoomForm({ ...roomForm, name: e.target.value })}
                        required
                        className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-[#E8A435]"
                      />
                      <input
                        type="number"
                        placeholder="Price per night"
                        value={roomForm.price}
                        onChange={(e) => setRoomForm({ ...roomForm, price: e.target.value })}
                        required
                        className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-[#E8A435]"
                      />
                      <input
                        type="number"
                        placeholder="Capacity"
                        value={roomForm.capacity}
                        onChange={(e) => setRoomForm({ ...roomForm, capacity: e.target.value })}
                        required
                        className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-[#E8A435]"
                      />
                      <input
                        type="text"
                        placeholder='Images (JSON array)'
                        value={roomForm.images}
                        onChange={(e) => setRoomForm({ ...roomForm, images: e.target.value })}
                        className="border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-[#E8A435]"
                      />
                    </div>
                    <textarea
                      placeholder="Description"
                      value={roomForm.description}
                      onChange={(e) => setRoomForm({ ...roomForm, description: e.target.value })}
                      required
                      rows={2}
                      className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-[#E8A435]"
                    />
                    <input
                      type="text"
                      placeholder='Amenities (JSON array, e.g. ["WiFi","Pool"])'
                      value={roomForm.amenities}
                      onChange={(e) => setRoomForm({ ...roomForm, amenities: e.target.value })}
                      className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-[#E8A435]"
                    />
                    <button
                      type="submit"
                      className="bg-[#1A4B7A] text-[#FAF3E0] px-6 py-2 rounded-lg font-medium hover:bg-[#1A4B7A]/90 transition-colors"
                    >
                      {editingRoom ? "Update" : "Create"}
                    </button>
                  </form>
                )}

                <div className="bg-white rounded-xl shadow-lg overflow-hidden">
                  <table className="w-full text-sm">
                    <thead className="bg-[#1A4B7A] text-[#FAF3E0]">
                      <tr>
                        <th className="text-left px-4 py-3">Name</th>
                        <th className="text-left px-4 py-3">Price</th>
                        <th className="text-left px-4 py-3">Bookings</th>
                        <th className="text-left px-4 py-3">Reviews</th>
                        <th className="text-right px-4 py-3">Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {rooms.map((room) => (
                        <tr key={room.id} className="border-b border-gray-100 hover:bg-gray-50">
                          <td className="px-4 py-3 font-medium">{room.name}</td>
                          <td className="px-4 py-3">€{room.price}</td>
                          <td className="px-4 py-3">{room._count.bookings}</td>
                          <td className="px-4 py-3">{room._count.reviews}</td>
                          <td className="px-4 py-3 text-right space-x-2">
                            <button
                              onClick={() => openEditRoom(room)}
                              className="text-[#1A4B7A] hover:underline text-xs"
                            >
                              Edit
                            </button>
                            <button
                              onClick={() => handleDeleteRoom(room.id)}
                              className="text-[#C75B39] hover:underline text-xs"
                            >
                              Delete
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                  {rooms.length === 0 && (
                    <p className="text-center text-gray-500 py-8">No rooms found</p>
                  )}
                </div>
              </div>
            )}

            {/* Bookings Tab */}
            {activeTab === "bookings" && (
              <div>
                <h2 className="font-playfair text-xl font-bold text-[#1A4B7A] mb-4">
                  All Bookings
                </h2>
                {bookings.length === 0 ? (
                  <p className="text-center text-gray-500 py-8">No bookings yet</p>
                ) : (
                  <div className="bg-white rounded-xl shadow-lg overflow-hidden">
                    <table className="w-full text-sm">
                      <thead className="bg-[#1A4B7A] text-[#FAF3E0]">
                        <tr>
                          <th className="text-left px-4 py-3">Guest</th>
                          <th className="text-left px-4 py-3">Room</th>
                          <th className="text-left px-4 py-3">Dates</th>
                          <th className="text-left px-4 py-3">Total</th>
                          <th className="text-left px-4 py-3">Status</th>
                          <th className="text-left px-4 py-3">Payment</th>
                        </tr>
                      </thead>
                      <tbody>
                        {bookings.map((b) => (
                          <tr key={b.id} className="border-b border-gray-100 hover:bg-gray-50">
                            <td className="px-4 py-3">
                              <div className="font-medium">{b.user?.name || "N/A"}</div>
                              <div className="text-xs text-gray-500">{b.user?.email}</div>
                            </td>
                            <td className="px-4 py-3">{b.room?.name || "N/A"}</td>
                            <td className="px-4 py-3 text-xs">
                              {formatDate(b.checkIn)} — {formatDate(b.checkOut)}
                            </td>
                            <td className="px-4 py-3 font-medium">€{b.totalPrice}</td>
                            <td className="px-4 py-3">
                              <select
                                value={b.status}
                                onChange={(e) => handleUpdateBookingStatus(b.id, e.target.value)}
                                disabled={updatingBooking === b.id}
                                className="text-xs border border-gray-300 rounded px-2 py-1 capitalize"
                              >
                                <option value="confirmed">Confirmed</option>
                                <option value="checked-in">Checked In</option>
                                <option value="completed">Completed</option>
                                <option value="cancelled">Cancelled</option>
                              </select>
                            </td>
                            <td className="px-4 py-3">
                              <span
                                className={`text-xs px-2 py-1 rounded-full font-medium ${
                                  b.paymentStatus === "paid"
                                    ? "bg-[#5A8F6E]/10 text-[#5A8F6E]"
                                    : "bg-[#E8A435]/10 text-[#C75B39]"
                                }`}
                              >
                                {b.paymentStatus}
                              </span>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            )}

            {/* Reviews Tab */}
            {activeTab === "reviews" && (
              <div>
                <h2 className="font-playfair text-xl font-bold text-[#1A4B7A] mb-4">
                  All Reviews
                </h2>
                {reviews.length === 0 ? (
                  <p className="text-center text-gray-500 py-8">No reviews yet</p>
                ) : (
                  <div className="space-y-4">
                    {reviews.map((review) => (
                      <div
                        key={review.id}
                        className="bg-white rounded-xl shadow-md p-5"
                      >
                        <div className="flex items-start justify-between">
                          <div>
                            <h3 className="font-playfair font-bold text-[#1A4B7A]">
                              {review.room?.name || "Unknown"}
                            </h3>
                            <p className="text-sm text-gray-500">
                              by {review.user?.name || "Anonymous"} • {formatDate(review.createdAt)}
                            </p>
                            <div className="flex gap-0.5 mt-1">
                              {[1, 2, 3, 4, 5].map((star) => (
                                <span
                                  key={star}
                                  className={`text-sm ${star <= review.rating ? "text-[#E8A435]" : "text-gray-300"}`}
                                >
                                  ★
                                </span>
                              ))}
                            </div>
                          </div>
                          <button
                            onClick={() => handleDeleteReview(review.id)}
                            className="text-[#C75B39] hover:underline text-xs"
                          >
                            Delete
                          </button>
                        </div>
                        <p className="text-gray-700 mt-3">{review.comment}</p>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Users Tab */}
            {activeTab === "users" && (
              <div>
                <h2 className="font-playfair text-xl font-bold text-[#1A4B7A] mb-4">
                  Users
                </h2>
                {users.length === 0 ? (
                  <p className="text-center text-gray-500 py-8">No users yet</p>
                ) : (
                  <div className="bg-white rounded-xl shadow-lg overflow-hidden">
                    <table className="w-full text-sm">
                      <thead className="bg-[#1A4B7A] text-[#FAF3E0]">
                        <tr>
                          <th className="text-left px-4 py-3">Name</th>
                          <th className="text-left px-4 py-3">Email</th>
                          <th className="text-left px-4 py-3">Role</th>
                          <th className="text-left px-4 py-3">Activity</th>
                          <th className="text-right px-4 py-3">Actions</th>
                        </tr>
                      </thead>
                      <tbody>
                        {users.map((user) => (
                          <tr key={user.id} className="border-b border-gray-100 hover:bg-gray-50">
                            <td className="px-4 py-3 font-medium">{user.name || "N/A"}</td>
                            <td className="px-4 py-3 text-xs">{user.email}</td>
                            <td className="px-4 py-3">
                              <select
                                value={user.role}
                                onChange={(e) => handleUpdateUserRole(user.id, e.target.value)}
                                className="text-xs border border-gray-300 rounded px-2 py-1"
                              >
                                <option value="user">User</option>
                                <option value="admin">Admin</option>
                              </select>
                            </td>
                            <td className="px-4 py-3 text-xs text-gray-500">
                              {user._count.bookings}b / {user._count.reviews}r / {user._count.favorites}f
                            </td>
                            <td className="px-4 py-3 text-right text-xs text-gray-500">
                              {formatDate(user.createdAt)}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}
